INSERT INTO site_content (key, value, updated_at) VALUES ('hero_slides_ru', '[{"tag":"новинка","title":"atk gear ghost ultimate","subtitle":"бескомпромиссная игровая мышь с уникальным дизайном","accent":"никаких компромиссов в производительности","image":"https://images.unsplash.com/photo-1527864550417-7fd91fc51a46?w=1400&q=80","detailsUrl":""},{"tag":"хит продаж","title":"razer viper v4 pro","subtitle":"ультралегкая беспроводная имба","accent":"оптический сенсор 50k dpi","image":"https://images.unsplash.com/photo-1615663245857-ac93bb7c39e7?w=1400&q=80","detailsUrl":""},{"tag":"лимитка","title":"logitech g pro superlight 2 yellow edition","subtitle":"создана вместе с киберспортсменами со всего мира","accent":"сенсор hero 25600 внутри","image":"https://images.unsplash.com/photo-1563297007-0686b7003af7?w=1400&q=80","detailsUrl":""}]'::jsonb, NOW()) ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = NOW();
INSERT INTO site_content (key, value, updated_at) VALUES ('hero_slides_en', '[{"tag":"new arrival","title":"atk gear ghost ultimate","subtitle":"the most unique gaming device in our store","accent":"no performance compromises","image":"https://images.unsplash.com/photo-1527864550417-7fd91fc51a46?w=1400&q=80","detailsUrl":""},{"tag":"top seller","title":"razer viper v3 pro","subtitle":"ultra-lightweight wireless freedom","accent":"25k dpi optical sensor","image":"https://images.unsplash.com/photo-1615663245857-ac93bb7c39e7?w=1400&q=80","detailsUrl":""},{"tag":"limited","title":"logitech g pro x","subtitle":"designed with pro players worldwide","accent":"hero 25600 sensor inside","image":"https://images.unsplash.com/photo-1563297007-0686b7003af7?w=1400&q=80","detailsUrl":""}]'::jsonb, NOW()) ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = NOW();
INSERT INTO site_content (key, value, updated_at) VALUES ('homepage_categories_ru', '[{"catalogKey":"products.categories.mice","title":"мышки","image":"https://polzarium.ru/content/images/2025/05/0-7.jpg"},{"catalogKey":"products.categories.mousepads","title":"коврики","image":"https://ae01.alicdn.com/kf/Sdf5307d2047f4386b59dde83ff7df080r.png"},{"catalogKey":"products.categories.keyboards","title":"клавиатуры","image":"https://iqunix.com/cdn/shop/files/07_ef9ac2e6-4b41-471b-af02-4b537819110b.jpg?v=1765951802&width=1946"},{"catalogKey":"products.categories.headsets","title":"наушники","image":"https://i.ytimg.com/vi/AbOziOlBiMk/maxresdefault.jpg"},{"catalogKey":"products.categories.glides","title":"глайды / грипсы","image":"https://www.deltamechanics.ru/pictures/product/big/20100_big.jpg"},{"catalogKey":"products.categories.accessories","title":"аксессуары","image":"https://fbi.cults3d.com/uploaders/14107503/illustration-file/1080cada-90f7-4eef-a8fe-a112bfde6460/cyberpunk_edgerunners_keycaps_04.jpg"}]'::jsonb, NOW()) ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = NOW();
INSERT INTO site_content (key, value, updated_at) VALUES ('homepage_categories_en', '[{"catalogKey":"products.categories.mice","title":"mice","image":"https://polzarium.ru/content/images/2025/05/0-7.jpg"},{"catalogKey":"products.categories.mousepads","title":"mousepads","image":"https://ae01.alicdn.com/kf/Sdf5307d2047f4386b59dde83ff7df080r.png"},{"catalogKey":"products.categories.keyboards","title":"keyboards","image":"https://iqunix.com/cdn/shop/files/07_ef9ac2e6-4b41-471b-af02-4b537819110b.jpg?v=1765951802&width=1946"},{"catalogKey":"products.categories.headsets","title":"headsets","image":"https://i.ytimg.com/vi/AbOziOlBiMk/maxresdefault.jpg"},{"catalogKey":"products.categories.glides","title":"glides / grips","image":"https://www.deltamechanics.ru/pictures/product/big/20100_big.jpg"},{"catalogKey":"products.categories.accessories","title":"accessories","image":"https://fbi.cults3d.com/uploaders/14107503/illustration-file/1080cada-90f7-4eef-a8fe-a112bfde6460/cyberpunk_edgerunners_keycaps_04.jpg"}]'::jsonb, NOW()) ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = NOW();
INSERT INTO site_content (key, value, updated_at) VALUES ('homepage_perks_ru', '[{"title":"гарантия качества","desc":"каждая позиция в каталоге проходит тщательное тестирование перед тем, как попасть к вам. гарантийное обслуживание и поддержка специалистов включены."},{"title":"быстрая доставка по стране","desc":"средний срок доставки составляет 3 рабочих дня. отправляем через CDEK с трекингом и уведомлениями на каждом этапе."},{"title":"0 фейковых отзывов","desc":"реальная обратная связь от игроков, которые уже протестировали наше железо. доверие и честная рекомендация для нас важнее громких обещаний."}]'::jsonb, NOW()) ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = NOW();
INSERT INTO site_content (key, value, updated_at) VALUES ('homepage_perks_en', '[{"title":"quality guarantee","desc":"every item in our catalog goes through rigorous expert testing before it reaches your hands. warranty service and specialist support included."},{"title":"fast delivery nationwide","desc":"average delivery time is 3 business days. shipped via CDEK with tracking and email updates on every status change."},{"title":"0 verified reviews","desc":"real feedback from thousands of gamers who''ve already tested our gear. your trust is our most important metric."}]'::jsonb, NOW()) ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = NOW();
INSERT INTO site_content (key, value, updated_at) VALUES ('homepage_news_ru', '[{"id":"fenrir","tag":"обзоры","readMin":"5 мин чтения","title":"удивительная малютка G-Wolves Fenrir Asym","excerpt":"сегодня мы подробно разберем игровую мышь G-Wolves Fenrir Asym. она была создана строго для одной цели — использования пальцевым хватом (fingertip grip).","body":"g-wolves fenrir asym — это специализированная мышь под fingertip grip.\n\nна тестах она показывает себя как лёгкая и манёвренная — 49 грамм веса, мягкий клик, paw3950 внутри.\n\nдля palm/claw она подойдёт хуже из-за крайне низкого профиля.","image":"https://images.unsplash.com/photo-1527864550417-7fd91fc51a46?w=1200&q=80","url":"/catalog"},{"id":"zywoo","tag":"обзоры","readMin":"4 мин чтения","title":"ZywOo x Pulsar: «оружие избранного»","excerpt":"компания pulsar совместно с главной звездой CS2 матье «zywoo» эрбо выпустили именную мышь. это не просто девайс с логотипом, а инструмент.","body":"pulsar x9 zywoo edition — это форма xlite v3 с отдельной прошивкой и кейкомпом, тюнингованным под профессиональную руку.\n\nцена дороже базовой версии, но в комплекте идут уникальные глайды и pvc-наклейки.","image":"https://images.unsplash.com/photo-1615663245857-ac93bb7c39e7?w=1200&q=80","url":"/catalog"},{"id":"modding","tag":"гайды","readMin":"7 мин чтения","title":"смазка свитчей: с чего начать новичку","excerpt":"выбираем смазку под свой кейкорд, разбираем порядок работ и показываем разницу до и после.","body":"для линейных свитчей берите krytox 205g0 — золотой стандарт.\n\nдля тактильных — что-то посуше: 3203 или вообще без смазки на ножке.\n\nпорядок: разбор → смазка стебля и пружины → сборка → тест.","image":"https://images.unsplash.com/photo-1593640408182-31c70c8268f5?w=1200&q=80","url":"/modding"}]'::jsonb, NOW()) ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = NOW();
INSERT INTO site_content (key, value, updated_at) VALUES ('homepage_news_en', '[{"id":"fenrir","tag":"reviews","readMin":"5 min read","title":"The tiny G-Wolves Fenrir Asym","excerpt":"A deep dive into the G-Wolves Fenrir Asym — a mouse built specifically for fingertip grip.","body":"g-wolves fenrir asym is a specialized fingertip mouse.\n\nin testing it feels light and snappy — 49g weight, soft click, paw3950 inside.\n\nnot great for palm/claw because of the extremely low profile.","image":"https://images.unsplash.com/photo-1527864550417-7fd91fc51a46?w=1200&q=80","url":"/catalog"},{"id":"zywoo","tag":"reviews","readMin":"4 min read","title":"ZywOo x Pulsar: weapon of the chosen","excerpt":"Pulsar teamed up with CS2''s top player Mathieu ''ZywOo'' Herbaut to release a signature mouse — not just a logo product.","body":"pulsar x9 zywoo edition uses the xlite v3 shape with a custom firmware and weight balance tuned for a pro hand.\n\npricier than the base version but comes with unique glides and pvc stickers.","image":"https://images.unsplash.com/photo-1615663245857-ac93bb7c39e7?w=1200&q=80","url":"/catalog"},{"id":"modding","tag":"guides","readMin":"7 min read","title":"Switch lubing 101 for beginners","excerpt":"How to pick the right lube, the basic workflow, and the before/after on popular switches.","body":"for linear switches use krytox 205g0 — the gold standard.\n\nfor tactiles go drier: 3203 or no lube on the leg.\n\nworkflow: disassemble → lube stem and spring → reassemble → test.","image":"https://images.unsplash.com/photo-1593640408182-31c70c8268f5?w=1200&q=80","url":"/modding"}]'::jsonb, NOW()) ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = NOW();
INSERT INTO site_content (key, value, updated_at) VALUES ('about_data_ru', '{"eyebrow":"о нас","title":"kolman.shop","subtitle":"магазин игровой периферии с прямыми поставками из китая — без лишних посредников и накруток.","heroPrimary":"в каталог","heroSecondary":"написать в telegram","polaroidTag":"наш формат","polaroidTitle":"честно, прямо, без наценок","storyTitle":"как устроена поставка","storyText":"у нас есть проверенный поставщик в китае, через которого мы напрямую завозим игровую периферию в россию. без лишних наценок от дистрибьюторов — цена честная.","valuesTitle":"три простых принципа","contactLabel":"связь","contactTitle":"есть вопросы — пишите","contactText":"поможем подобрать мышь под хват и ладонь, клавиатуру под задачи, посоветуем что взять при ограниченном бюджете. пишите в телеграм или на авито — отвечаем быстро.","avitoBtn":"авито","emailBtn":"написать на почту","stats":[{"value":"20+","label":"брендов в каталоге"},{"value":"1500+","label":"выполненных заказов"},{"value":"3 дня","label":"средняя доставка"},{"value":"14 дней","label":"обмен и возврат"}],"timeline":[{"num":"01","title":"производитель","text":"отбираем актуальные модели у проверенных фабрик и брендов."},{"num":"02","title":"склад в КНР","text":"консолидируем заказ, проверяем комплектность и упаковку."},{"num":"03","title":"логистика","text":"отправляем партией в Россию, проходим таможню белым каналом."},{"num":"04","title":"CDEK и вы","text":"отправляем CDEK с трекингом, доставляем за 3-7 дней."}],"values":[{"num":"01","title":"честные цены","text":"между вами и производителем нет лишних звеньев — отсюда и цена."},{"num":"02","title":"личный сервис","text":"отвечаем сами, без скриптов и колл-центра. помогаем с выбором."},{"num":"03","title":"гарантия","text":"обмен или возврат в течение 14 дней — без лишних вопросов."}]}'::jsonb, NOW()) ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = NOW();
INSERT INTO site_content (key, value, updated_at) VALUES ('about_data_en', '{"eyebrow":"about us","title":"kolman.shop","subtitle":"a gaming peripherals store with direct imports from China — no middlemen, no markups.","heroPrimary":"shop catalog","heroSecondary":"message us","polaroidTag":"our approach","polaroidTitle":"honest, direct, no markups","storyTitle":"how supply works","storyText":"we have a vetted supplier in China who lets us import peripherals directly to Russia — no extra distributor markup. the price is fair because there''s nothing in between.","valuesTitle":"three simple principles","contactLabel":"contact","contactTitle":"have questions — write us","contactText":"message us on Telegram or Avito — we reply fast.","avitoBtn":"avito","emailBtn":"send an email","stats":[{"value":"20+","label":"brands in catalog"},{"value":"1500+","label":"orders shipped"},{"value":"3 days","label":"average delivery"},{"value":"14 days","label":"returns & exchange"}],"timeline":[{"num":"01","title":"manufacturer","text":"we pick current models from trusted factories and brands."},{"num":"02","title":"warehouse in CN","text":"consolidate the order, check packaging and completeness."},{"num":"03","title":"logistics","text":"ship in batches to Russia, customs handled the white way."},{"num":"04","title":"CDEK & you","text":"CDEK with tracking, 3-7 days to your door."}],"values":[{"num":"01","title":"fair pricing","text":"no middlemen between you and the factory — that''s where the price comes from."},{"num":"02","title":"personal service","text":"we answer ourselves, no call center, no scripts. we help you choose."},{"num":"03","title":"warranty","text":"exchange or refund within 14 days — no awkward questions."}]}'::jsonb, NOW()) ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = NOW();
INSERT INTO site_content (key, value, updated_at) VALUES ('partnership_data_ru', '{"eyebrow":"партнерство","title":"работаем вместе","subtitle":"для блогеров, стримеров, реселлеров и B2B клиентов — особые условия и прямой контакт.","popularBadge":"популярно","tierCtaPrimary":"обсудить условия","tierCtaSecondary":"написать в telegram","perksTitle":"почему партнёры с нами","ctaLabel":"написать по партнерству","ctaText":"расскажите о своём проекте — обсудим форматы сотрудничества.","telegramBtn":"написать в telegram","emailBtn":"написать на почту","tiers":[{"id":"creator","name":"контент-мейкеры","priceLabel":"персонально","priceNote":"обсуждается под проект","features":["железо на тест и обзоры","промокоды и реферальные ссылки","персональный менеджер","эксклюзивные новинки до релиза"]},{"id":"reseller","name":"реселлеры","priceLabel":"от 5 единиц","priceNote":"оптовая цена и логистика","featured":true,"features":["оптовые цены от 5 шт.","прямые поставки без посредников","консолидация заказа на нашем складе","гарантия и поддержка после продажи","обмен брака без вопросов"]},{"id":"b2b","name":"B2B и организации","priceLabel":"индивидуально","priceNote":"кибер-клубы, офисы, обучение","features":["комплектное оснащение рабочих мест","договор и закрывающие документы","отсрочка платежа для постоянных","оперативная замена при поломках"]}],"perks":[{"title":"прямая поставка","text":"без посредников и наценок"},{"title":"честные цены","text":"один прайс для всех"},{"title":"быстрая логистика","text":"отправка в день оплаты"},{"title":"личный контакт","text":"отвечаем сами, не бот"}]}'::jsonb, NOW()) ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = NOW();
INSERT INTO site_content (key, value, updated_at) VALUES ('partnership_data_en', '{"eyebrow":"partnership","title":"work with us","subtitle":"for creators, resellers, and B2B clients — special terms and direct contact.","popularBadge":"popular","tierCtaPrimary":"discuss terms","tierCtaSecondary":"write on telegram","perksTitle":"why partners pick us","ctaLabel":"get in touch","ctaText":"tell us about your project — we will discuss partnership formats.","telegramBtn":"write on telegram","emailBtn":"send an email","tiers":[{"id":"creator","name":"creators","priceLabel":"custom","priceNote":"per-project terms","features":["gear for review and testing","promo codes and affiliate links","dedicated manager","early access to new arrivals"]},{"id":"reseller","name":"resellers","priceLabel":"from 5 units","priceNote":"wholesale price and logistics","featured":true,"features":["wholesale pricing from 5 units","direct imports, no middlemen","consolidation at our warehouse","after-sale warranty and support","no-questions defect exchange"]},{"id":"b2b","name":"B2B & orgs","priceLabel":"tailored","priceNote":"cybercafes, offices, training","features":["full workstation outfitting","contracts and closing documents","deferred payments for regulars","fast replacements on failures"]}],"perks":[{"title":"direct supply","text":"no middlemen or markups"},{"title":"honest pricing","text":"one price for everyone"},{"title":"fast logistics","text":"ships the day you pay"},{"title":"real human contact","text":"we reply ourselves, not a bot"}]}'::jsonb, NOW()) ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = NOW();
INSERT INTO site_content (key, value, updated_at) VALUES ('delivery_data_ru', '{"eyebrow":"доставка и оплата","title":"получите ваш заказ","subtitle":"доставляем по всей России через CDEK. большинство позиций отправляем в день заказа.","statusChip":"работаем с CDEK","timelineTitle":"как доходит ваш заказ","paymentTitle":"способы оплаты","coverageTitle":"сроки по регионам","faqTitle":"частые вопросы","timeline":[{"num":"01","title":"заказ","text":"оформляете на сайте или через авито."},{"num":"02","title":"подготовка","text":"проверяем комплектацию и упаковываем."},{"num":"03","title":"отправка","text":"передаём в CDEK с трекинг-номером."},{"num":"04","title":"у вас","text":"забираете в пункте выдачи или курьером."}],"payment":[{"name":"Тинькофф","text":"перевод по номеру карты или СБП"},{"name":"Сбер","text":"СБП и переводы по номеру"},{"name":"Авито Доставка","text":"безопасная сделка через площадку"},{"name":"при получении","text":"наложенный платёж по согласованию"}],"coverage":[{"region":"Москва и МО","text":"2-3 дня"},{"region":"Санкт-Петербург","text":"3-4 дня"},{"region":"центр и юг РФ","text":"4-6 дней"},{"region":"Урал и Сибирь","text":"5-8 дней"},{"region":"Дальний Восток","text":"7-10 дней"}],"faq":[{"q":"можно получить заказ в день покупки?","a":"нет, мы работаем только с доставкой по России через CDEK. самовывоз не предусмотрен."},{"q":"как отследить посылку?","a":"после отправки вышлем номер отслеживания CDEK на telegram или email."},{"q":"что делать если пришёл не тот товар?","a":"напишите нам с фото — организуем замену или возврат за наш счёт."},{"q":"есть ли доставка в страны СНГ?","a":"пока нет, работаем только по России. но планируем расширяться."}]}'::jsonb, NOW()) ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = NOW();
INSERT INTO site_content (key, value, updated_at) VALUES ('delivery_data_en', '{"eyebrow":"shipping & payment","title":"get your order","subtitle":"we ship across Russia via CDEK. most items go out the same day.","statusChip":"shipping via CDEK","timelineTitle":"how your order travels","paymentTitle":"payment methods","coverageTitle":"delivery times by region","faqTitle":"faq","timeline":[{"num":"01","title":"order","text":"place it on the site or via Avito."},{"num":"02","title":"prep","text":"we check the kit and pack carefully."},{"num":"03","title":"ship","text":"handed off to CDEK with a tracking number."},{"num":"04","title":"arrived","text":"pick up at the point or get courier delivery."}],"payment":[{"name":"Tinkoff","text":"card transfer or SBP"},{"name":"Sber","text":"SBP and card transfers"},{"name":"Avito Delivery","text":"safe checkout via the platform"},{"name":"on receipt","text":"cash on delivery by arrangement"}],"coverage":[{"region":"Moscow region","text":"2-3 days"},{"region":"Saint Petersburg","text":"3-4 days"},{"region":"central & south RU","text":"4-6 days"},{"region":"Urals & Siberia","text":"5-8 days"},{"region":"Far East","text":"7-10 days"}],"faq":[{"q":"can i pick up my order on the same day?","a":"no, we only ship within Russia via CDEK. no local pickup available."},{"q":"how do i track my order?","a":"once shipped, we will send you a CDEK tracking number via telegram or email."},{"q":"what if i received the wrong item?","a":"send us a photo — we will organise a replacement or refund at our expense."},{"q":"do you ship to CIS countries?","a":"not yet, we currently only ship within Russia. expansion is planned."}]}'::jsonb, NOW()) ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = NOW();
INSERT INTO site_content (key, value, updated_at) VALUES ('modding_data_ru', '{"eyebrow":"кастомизация","titleStart":"раскройте","titleAccent":"потенциал","titleEnd":"своих девайсов.","subtitle":"профессиональный моддинг — это не просто ремонт. это возможность сделать вашу клавиатуру тише, а мышь — быстрее и точнее.","processTitle":"процесс работы","bundlesTitle":"комплекты с выгодой","bundlesSubtitle":"готовые решения для комплексного апгрейда","perks":[{"title":"идеальный звук","text":"убираем паразитные звуки, пружинный звон и дребезг. добиваемся благородного «тайпинга»."},{"title":"комфорт и контроль","text":"плавный ход клавиш и безупречное скольжение мыши для стабильности в катках."},{"title":"надёжность","text":"профилактика износа и использование лучших расходных материалов продлевают жизнь девайса."}],"processSteps":[{"step":"шаг 1","title":"оплата и доставка","text":"оплачиваете услугу, передаёте девайс в Москве или отправляете через СДЭК."},{"step":"шаг 2","title":"моддинг (5-10 дней)","text":"наши мастера аккуратно разбирают, чистят, смазывают и улучшают ваше устройство."},{"step":"шаг 3","title":"проверка и возврат","text":"тестируем результат и отправляем вам полностью прокачанный девайс с гарантией 30 дней."}],"services":[{"id":"switch-lube","category":"keyboards","tag":"популярно","title":"смазка свитчей клавиатуры","desc":"профессиональная смазка механических и магнитных свитчей для идеального хода.","features":["плавный ход клавиш","снижение пружинного звона","улучшение стабильности","снижение износа"],"price":"от 3 000₽"},{"id":"stab-tune","category":"keyboards","title":"корректировка стабилизаторов","desc":"доработка и смазка стабилизаторов для устранения дребезга.","features":["полное устранение дребезга","чистый звук длинных клавиш","ровный ход без заеданий","балансировка"],"price":"1 000₽"},{"id":"kb-clean","category":"keyboards","title":"чистка клавиатуры","desc":"глубокая очистка кейкапов и корпуса от пыли и загрязнений.","features":["восстановление вида","гигиеническая обработка","удаление мелкого мусора"],"price":"1 500₽"},{"id":"glides","category":"mice","tag":"апгрейд","title":"установка глайдов","desc":"замена штатных тефлоновых ножек на премиальные глайды ProAim / Tiger Ice.","features":["безупречное скольжение","аккуратная подгонка","без люфтов и зазоров"],"price":"от 1 500₽"},{"id":"micro","category":"mice","title":"замена микриков","desc":"установка качественных микропереключателей вместо изношенных или хрустящих.","features":["чёткий клик","без двойных срабатываний","выбор Kailh / Omron / TTC"],"price":"от 2 000₽"},{"id":"encoder","category":"mice","title":"замена энкодера","desc":"установка нового энкодера колеса — против люфта и проскальзывания.","features":["чёткая прокрутка","без проскоков","тактильные шаги"],"price":"от 1 800₽"}],"bundles":[{"id":"mouse-full","savings":"экономия 500₽","title":"полный моддинг мыши","desc":"комплексное улучшение: глайды, микрики, энкодер и чистка сборки.","features":["глайды ProAim","новые переключатели","новый энкодер","техническое обслуживание"],"priceOld":"3 000₽","priceNew":"2 500₽","cta":"заказать"},{"id":"setup","savings":"экономия 2000₽","title":"игровой сетап","desc":"максимальный апгрейд вашей основной периферии.","features":["полный моддинг клавиатуры","полный моддинг мыши","индивидуальная настройка","чистка и уход"],"priceOld":"8 800₽","priceNew":"от 6 800₽","cta":"заказать"}],"finalCtaTitle":"есть вопросы по моддингу?","finalCtaText":"наши мастера помогут определиться со смазкой или подобрать микрики под ваш стиль клика.","finalCtaBtn":"написать мастеру"}'::jsonb, NOW()) ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = NOW();
INSERT INTO site_content (key, value, updated_at) VALUES ('modding_data_en', '{"eyebrow":"customization","titleStart":"unlock the","titleAccent":"potential","titleEnd":"of your devices.","subtitle":"professional modding is more than repair. it is how we make your keyboard quieter and your mouse faster and more precise.","processTitle":"how it works","bundlesTitle":"bundles with savings","bundlesSubtitle":"ready-made packages for a full upgrade","perks":[{"title":"perfect sound","text":"eliminate parasitic noise, spring ping and rattle. dial in a clean typing tone."},{"title":"comfort & control","text":"smooth key travel and flawless mouse glide for stable performance in matches."},{"title":"reliability","text":"wear prevention and premium materials extend device lifetime."}],"processSteps":[{"step":"step 1","title":"pay and ship","text":"pay for the service, hand the device in Moscow or send via CDEK."},{"step":"step 2","title":"modding (5-10 days)","text":"our masters carefully disassemble, clean, lubricate and tune your device."},{"step":"step 3","title":"qa and return","text":"we test the result and ship the fully tuned device with a 30-day warranty."}],"services":[{"id":"switch-lube","category":"keyboards","tag":"popular","title":"switch lubing","desc":"pro lubing for mechanical and magnetic switches — perfect key feel.","features":["smooth keystroke","reduced spring ping","better stability","less wear"],"price":"from 3 000₽"},{"id":"stab-tune","category":"keyboards","title":"stabilizer tuning","desc":"tuning and lubing stabilizers to remove rattle.","features":["no more rattle","clean sound on long keys","even travel, no binding","balancing"],"price":"1 000₽"},{"id":"kb-clean","category":"keyboards","title":"keyboard deep clean","desc":"deep cleaning of keycaps and case from dust and grime.","features":["cosmetic restore","sanitary treatment","debris removal"],"price":"1 500₽"},{"id":"glides","category":"mice","tag":"upgrade","title":"glide installation","desc":"swap stock feet for premium glides ProAim / Tiger Ice.","features":["flawless glide","precise fit","no play or gaps"],"price":"from 1 500₽"},{"id":"micro","category":"mice","title":"switch swap","desc":"replace worn micro-switches with quality alternatives.","features":["crisp click","no double-clicks","Kailh / Omron / TTC available"],"price":"from 2 000₽"},{"id":"encoder","category":"mice","title":"encoder replacement","desc":"new wheel encoder — no more wobble or slipping.","features":["crisp scrolling","no skips","tactile steps"],"price":"from 1 800₽"}],"bundles":[{"id":"mouse-full","savings":"save 500₽","title":"full mouse mod","desc":"glides, switches, encoder and deep clean — all in.","features":["ProAim glides","new switches","new encoder","maintenance"],"priceOld":"3 000₽","priceNew":"2 500₽","cta":"order"},{"id":"setup","savings":"save 2000₽","title":"gaming setup","desc":"the max upgrade for your main peripherals.","features":["full keyboard mod","full mouse mod","custom tuning","cleaning and care"],"priceOld":"8 800₽","priceNew":"from 6 800₽","cta":"order"}],"finalCtaTitle":"questions about modding?","finalCtaText":"our masters can help you pick lube or match switches to your click style.","finalCtaBtn":"message a master"}'::jsonb, NOW()) ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = NOW();
INSERT INTO site_content (key, value, updated_at) VALUES ('help_choose_data_ru', '{"eyebrow":"помочь с выбором","title":"подберём идеальный девайс","subtitle":"3 простых шага — и мы поймём, что вам нужно. дальше — личная консультация в telegram.","resultTitle":"почти готово — мы подберём вместе","resultText":"на основе ответов посоветуем 2-3 варианта под ваш бюджет и задачи. бесплатно и без обязательств — пишите.","resetBtn":"сбросить ответы","telegramBtn":"написать в telegram","supportBtn":"форма на сайте","steps":[{"question":"для чего нужен девайс?","options":[{"id":"shooter","label":"шутеры и киберспорт","hint":"лёгкая мышь + быстрый коврик"},{"id":"mmo","label":"mmo / стратегии","hint":"удобная форма, доп. кнопки"},{"id":"work","label":"работа и учёба","hint":"тихие свитчи, эргономика"},{"id":"stream","label":"стриминг и контент","hint":"эстетика и звук"}]},{"question":"какой бюджет?","options":[{"id":"budget","label":"до 5 000₽","hint":"умные базовые модели"},{"id":"mid","label":"5 000 – 15 000₽","hint":"оптимум по цене/качеству"},{"id":"premium","label":"15 000₽+","hint":"флагманы и редкости"}]},{"question":"что важнее всего?","options":[{"id":"speed","label":"скорость и точность"},{"id":"comfort","label":"комфорт на долгие сессии"},{"id":"sound","label":"звук и тактильность"},{"id":"look","label":"внешний вид сетапа"}]}]}'::jsonb, NOW()) ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = NOW();
INSERT INTO site_content (key, value, updated_at) VALUES ('help_choose_data_en', '{"eyebrow":"help me choose","title":"find the perfect device","subtitle":"3 quick steps and we know what you need — then a personal consult on telegram.","resultTitle":"almost there — let us pick together","resultText":"we''ll suggest 2-3 options based on your answers. free, no strings — message us.","resetBtn":"reset answers","telegramBtn":"write on telegram","supportBtn":"use the form","steps":[{"question":"what is the device for?","options":[{"id":"shooter","label":"shooters and esports","hint":"light mouse + fast pad"},{"id":"mmo","label":"mmo / strategy","hint":"shape and extra buttons"},{"id":"work","label":"work and study","hint":"quiet switches, ergonomics"},{"id":"stream","label":"streaming and content","hint":"aesthetics and sound"}]},{"question":"what is your budget?","options":[{"id":"budget","label":"up to 5 000₽","hint":"smart entry models"},{"id":"mid","label":"5 000 – 15 000₽","hint":"sweet spot"},{"id":"premium","label":"15 000₽+","hint":"flagships and rarities"}]},{"question":"what matters most?","options":[{"id":"speed","label":"speed and accuracy"},{"id":"comfort","label":"comfort for long sessions"},{"id":"sound","label":"sound and feel"},{"id":"look","label":"how the setup looks"}]}]}'::jsonb, NOW()) ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value, updated_at = NOW();
